changeSet.sql:
DECLARE @userA BIGINT = (SELECT id FROM users WHERE username = 'nguyenvana');
DECLARE @userB BIGINT = (SELECT id FROM users WHERE username = 'tranthib');
DECLARE @userC BIGINT = (SELECT id FROM users WHERE username = 'levanc');
DECLARE @adminId BIGINT = (SELECT id FROM users WHERE username = 'admin');

DECLARE @st1 BIGINT = (SELECT TOP 1 id FROM showtimes WHERE status = 'FINISHED' ORDER BY id ASC);
DECLARE @st2 BIGINT = (SELECT id FROM showtimes WHERE status = 'FINISHED' ORDER BY id ASC OFFSET 1 ROWS FETCH NEXT 1 ROWS ONLY);
DECLARE @st3 BIGINT = (SELECT TOP 1 id FROM showtimes WHERE status = 'FINISHED' ORDER BY id DESC);
DECLARE @stToday BIGINT = (SELECT TOP 1 id FROM showtimes WHERE status = 'SCHEDULED' ORDER BY id ASC);

DECLARE @r1 BIGINT = (SELECT id FROM rooms WHERE name = N'Phòng 01');
DECLARE @r2 BIGINT = (SELECT id FROM rooms WHERE name = N'Phòng 02');

DECLARE @i INT = 1;
DECLARE @code NVARCHAR(30);
DECLARE @payCode NVARCHAR(30);
DECLARE @userId BIGINT;
DECLARE @stId BIGINT;
DECLARE @status NVARCHAR(20);
DECLARE @amount DECIMAL(12,0);
DECLARE @payStatus NVARCHAR(20);
DECLARE @dayOffset INT;
DECLARE @method NVARCHAR(20);

WHILE @i <= 50
BEGIN
    -- Xoay vòng user
    SET @userId = CASE @i % 4
        WHEN 0 THEN @userA
        WHEN 1 THEN @userB
        WHEN 2 THEN @userC
        WHEN 3 THEN @adminId
    END;

    -- Xoay vòng showtime
    SET @stId = CASE @i % 4
        WHEN 0 THEN @st1
        WHEN 1 THEN @st2
        WHEN 2 THEN @st3
        WHEN 3 THEN @stToday
    END;

    -- Xoay vòng status
    SET @status = CASE @i % 5
        WHEN 0 THEN 'CONFIRMED'
        WHEN 1 THEN 'CHECKED_IN'
        WHEN 2 THEN 'CONFIRMED'
        WHEN 3 THEN 'CANCELLED'
        WHEN 4 THEN 'HOLDING'
    END;

    -- Amount ngẫu nhiên
    SET @amount = 75000 + (@i % 7) * 25000;

    -- Ngày tạo ngẫu nhiên trong 14 ngày qua
    SET @dayOffset = -(@i % 14);

    -- Payment method xoay vòng
    SET @method = CASE @i % 3
        WHEN 0 THEN 'VNPAY'
        WHEN 1 THEN 'MOMO'
        WHEN 2 THEN 'CASH'
    END;

    SET @code = 'CX-SEED-' + RIGHT('000' + CAST(@i AS VARCHAR), 3);
    SET @payCode = 'PAY-SEED-' + RIGHT('000' + CAST(@i AS VARCHAR), 3);

    -- Insert booking
    INSERT INTO bookings (user_id, showtime_id, total_amount, status, booking_code,
        confirmed_at, cancelled_at, version, storage_state, created_by, created_at, updated_at)
    VALUES (
        @userId, @stId, @amount, @status, @code,
        CASE WHEN @status IN ('CONFIRMED','CHECKED_IN','CANCELLED') THEN DATEADD(day, @dayOffset, GETDATE()) ELSE NULL END,
        CASE WHEN @status = 'CANCELLED' THEN DATEADD(day, @dayOffset, GETDATE()) ELSE NULL END,
        0, 'ACTIVE', 'system',
        DATEADD(day, @dayOffset, GETDATE()),
        DATEADD(day, @dayOffset, GETDATE())
    );

    -- Insert payment (trừ HOLDING)
    IF @status != 'HOLDING'
    BEGIN
        DECLARE @bkId BIGINT = (SELECT id FROM bookings WHERE booking_code = @code);
        SET @payStatus = CASE
            WHEN @status = 'CANCELLED' THEN 'REFUNDED'
            ELSE 'COMPLETED'
        END;

        INSERT INTO payments (booking_id, amount, method, transaction_code, status, paid_at,
            version, storage_state, created_by, created_at, updated_at)
        VALUES (
            @bkId, @amount, @method, @payCode, @payStatus,
            DATEADD(day, @dayOffset, GETDATE()),
            0, 'ACTIVE', 'system',
            DATEADD(day, @dayOffset, GETDATE()),
            DATEADD(day, @dayOffset, GETDATE())
        );
    END;

    SET @i = @i + 1;
END;
